18	/// A thread-safe mutable memory location.
19	///
20	/// This type is equivalent to [`Cell`], except it can also be shared among multiple threads.
21	///
22	/// Operations on `AtomicCell`s use atomic instructions whenever possible, and synchronize using
23	/// global locks otherwise. You can call [`AtomicCell::<T>::is_lock_free()`] to check whether
24	/// atomic instructions or locks will be used.
25	///
26	/// Atomic loads use the [`Acquire`] ordering and atomic stores use the [`Release`] ordering.
27	///
28	/// [`Cell`]: std::cell::Cell
29	/// [`AtomicCell::<T>::is_lock_free()`]: AtomicCell::is_lock_free
30	/// [`Acquire`]: std::sync::atomic::Ordering::Acquire
31	/// [`Release`]: std::sync::atomic::Ordering::Release
32	#[repr(transparent)]
33	pub struct AtomicCell<T> {
34	    /// The inner value.
35	    ///
36	    /// If this value can be transmuted into a primitive atomic type, it will be treated as such.
37	    /// Otherwise, all potentially concurrent operations on this data will be protected by a global
38	    /// lock.
39	    ///
40	    /// Using MaybeUninit to prevent code outside the cell from observing partially initialized state:
41	    /// <https://github.com/crossbeam-rs/crossbeam/issues/833>
42	    /// (This rustc bug has been fixed in Rust 1.64.)
43	    ///
44	    /// Note:
45	    /// - we'll never store uninitialized `T` due to our API only using initialized `T`.
46	    /// - this `MaybeUninit` does *not* fix <https://github.com/crossbeam-rs/crossbeam/issues/315>.
47	    value: UnsafeCell<MaybeUninit<T>>,
48	}
49	
50	unsafe impl<T: Send> Send for AtomicCell<T> {}
51	unsafe impl<T: Send> Sync for AtomicCell<T> {}
52	
53	impl<T> UnwindSafe for AtomicCell<T> {}
54	impl<T> RefUnwindSafe for AtomicCell<T> {}
55	
56	impl<T> AtomicCell<T> {
57	    /// Creates a new atomic cell initialized with `val`.
58	    ///
59	    /// # Examples
60	    ///
61	    /// ```
62	    /// use crossbeam_utils::atomic::AtomicCell;
63	    ///
64	    /// let a = AtomicCell::new(7);
65	    /// ```
66	    pub const fn new(val: T) -> Self {
67	        Self {
68	            value: UnsafeCell::new(MaybeUninit::new(val)),
69	        }
70	    }
71	
72	    /// Consumes the atomic and returns the contained value.
73	    ///
74	    /// This is safe because passing `self` by value guarantees that no other threads are
75	    /// concurrently accessing the atomic data.
76	    ///
77	    /// # Examples
78	    ///
79	    /// ```
80	    /// use crossbeam_utils::atomic::AtomicCell;
81	    ///
82	    /// let a = AtomicCell::new(7);
83	    /// let v = a.into_inner();
84	    ///
85	    /// assert_eq!(v, 7);
86	    /// ```
87	    pub const fn into_inner(self) -> T {
88	        // HACK: This is equivalent to transmute_copy by value, but available in const
89	        // context even on older rustc (const transmute_copy requires Rust 1.74), and
90	        // can work around "cannot borrow here, since the borrowed element may contain
91	        // interior mutability" error occurs (until const_refs_to_cell stabilized, i.e.,
92	        // Rust 1.83) when using transmute_copy with generic type in const context
93	        // (because this is a by-value transmutation that doesn't create a reference to
94	        // the source value).
95	        /// # Safety
96	        ///
97	        /// This function has the same safety requirements as [`core::mem::transmute_copy`].
98	        ///
99	        /// Since this is a by-value transmutation, it copies the bits from the source value
100	        /// into the destination value, then forgets the original, as with the [`core::mem::transmute`].
101	        #[inline]
102	        #[must_use]
103	        const unsafe fn transmute_copy_by_val<Src, Dst>(src: Src) -> Dst {
104	            #[repr(C)]
105	            union ConstHack<Src, Dst> {
106	                src: ManuallyDrop<Src>,
107	                dst: ManuallyDrop<Dst>,
108	            }
109	            assert!(mem::size_of::<Src>() >= mem::size_of::<Dst>()); // assertion copied from transmute_copy
110	            // SAFETY: ConstHack is #[repr(C)] union, and the caller must guarantee that
111	            // transmuting Src to Dst is safe.
112	            ManuallyDrop::into_inner(unsafe {
113	                ConstHack::<Src, Dst> {
114	                    src: ManuallyDrop::new(src),
115	                }
116	                .dst
117	            })
118	        }
119	
120	        // SAFETY:
121	        // - Self is repr(transparent) over `UnsafeCell<MaybeUninit<T>>` and
122	        //   `UnsafeCell<MaybeUninit<T>>` and `T` has the same layout.
123	        // - passing `self` by value guarantees that no other threads are concurrently
124	        //   accessing the atomic data
125	        // (Equivalent to UnsafeCell::into_inner which is unstable in const context.)
126	        unsafe { transmute_copy_by_val(self) }
127	    }
128	
129	    /// Returns `true` if operations on values of this type are lock-free.
130	    ///
131	    /// If the compiler or the platform doesn't support the necessary atomic instructions,
132	    /// `AtomicCell<T>` will use global locks for every potentially concurrent atomic operation.
133	    ///
134	    /// # Examples
135	    ///
136	    /// ```
137	    /// # // Always use fallback for now on environments that do not support inline assembly.
138	    /// # if cfg!(any(miri, crossbeam_loom, crossbeam_atomic_cell_force_fallback)) { return; }
139	    /// # atomic_maybe_uninit::cfg_no_atomic_cas! { if true { return; } }
140	    /// use crossbeam_utils::atomic::AtomicCell;
141	    ///
142	    /// // This type is internally represented as `AtomicUsize` so we can just use atomic
143	    /// // operations provided by it.
144	    /// assert_eq!(AtomicCell::<usize>::is_lock_free(), true);
145	    ///
146	    /// // A wrapper struct around `isize`.
147	    /// struct Foo {
148	    ///     bar: isize,
149	    /// }
150	    /// // `AtomicCell<Foo>` will be internally represented as `AtomicIsize`.
151	    /// assert_eq!(AtomicCell::<Foo>::is_lock_free(), true);
152	    ///
153	    /// // Operations on zero-sized types are always lock-free.
154	    /// assert_eq!(AtomicCell::<()>::is_lock_free(), true);
155	    ///
156	    /// // Very large types cannot be represented as any of the standard atomic types, so atomic
157	    /// // operations on them will have to use global locks for synchronization.
158	    /// assert_eq!(AtomicCell::<[u8; 1000]>::is_lock_free(), false);
159	    /// ```
160	    pub const fn is_lock_free() -> bool {
161	        atomic_is_lock_free::<T>()
162	    }
163	
164	    /// Stores `val` into the atomic cell.
165	    ///
166	    /// # Examples
167	    ///
168	    /// ```
169	    /// use crossbeam_utils::atomic::AtomicCell;
170	    ///
171	    /// let a = AtomicCell::new(7);
172	    ///
173	    /// assert_eq!(a.load(), 7);
174	    /// a.store(8);
175	    /// assert_eq!(a.load(), 8);
176	    /// ```
177	    pub fn store(&self, val: T) {
178	        if mem::needs_drop::<T>() {
179	            drop(self.swap(val));
180	        } else {
181	            unsafe {
182	                atomic_store(self.as_ptr(), val);
183	            }
184	        }
185	    }
186	
187	    /// Stores `val` into the atomic cell and returns the previous value.
188	    ///
189	    /// # Examples
190	    ///
191	    /// ```
192	    /// use crossbeam_utils::atomic::AtomicCell;
193	    ///
194	    /// let a = AtomicCell::new(7);
195	    ///
196	    /// assert_eq!(a.load(), 7);
197	    /// assert_eq!(a.swap(8), 7);
198	    /// assert_eq!(a.load(), 8);
199	    /// ```
200	    pub fn swap(&self, val: T) -> T {
201	        unsafe { atomic_swap(self.as_ptr(), val) }
202	    }
203	
204	    /// Returns a raw pointer to the underlying data in this atomic cell.
205	    ///
206	    /// # Examples
207	    ///
208	    /// ```
209	    /// use crossbeam_utils::atomic::AtomicCell;
210	    ///
211	    /// let a = AtomicCell::new(5);
212	    ///
213	    /// let ptr = a.as_ptr();
214	    /// ```
215	    #[inline]
216	    pub const fn as_ptr(&self) -> *mut T {
217	        self.value.get().cast::<T>()
218	    }
219	}
220	
221	impl<T: Default> AtomicCell<T> {
222	    /// Takes the value of the atomic cell, leaving `Default::default()` in its place.
223	    ///
224	    /// # Examples
225	    ///
226	    /// ```
227	    /// use crossbeam_utils::atomic::AtomicCell;
228	    ///
229	    /// let a = AtomicCell::new(5);
230	    /// let five = a.take();
231	    ///
232	    /// assert_eq!(five, 5);
233	    /// assert_eq!(a.into_inner(), 0);
234	    /// ```
235	    pub fn take(&self) -> T {
236	        self.swap(Default::default())
237	    }
238	}
239	
240	impl<T: Copy> AtomicCell<T> {
241	    /// Loads a value from the atomic cell.
242	    ///
243	    /// # Examples
244	    ///
245	    /// ```
246	    /// use crossbeam_utils::atomic::AtomicCell;
247	    ///
248	    /// let a = AtomicCell::new(7);
249	    ///
250	    /// assert_eq!(a.load(), 7);
251	    /// ```
252	    pub fn load(&self) -> T {
253	        unsafe { atomic_load(self.as_ptr()) }
254	    }
255	}
256	
257	impl<T: Copy + Eq> AtomicCell<T> {
258	    /// If the current value equals `current`, stores `new` into the atomic cell.
259	    ///
260	    /// The return value is a result indicating whether the new value was written and containing
261	    /// the previous value. On success this value is guaranteed to be equal to `current`.
262	    ///
263	    /// # Examples
264	    ///
265	    /// ```
266	    /// use crossbeam_utils::atomic::AtomicCell;
267	    ///
268	    /// let a = AtomicCell::new(1);
269	    ///
270	    /// assert_eq!(a.compare_exchange(2, 3), Err(1));
271	    /// assert_eq!(a.load(), 1);
272	    ///
273	    /// assert_eq!(a.compare_exchange(1, 2), Ok(1));
274	    /// assert_eq!(a.load(), 2);
275	    /// ```
276	    pub fn compare_exchange(&self, current: T, new: T) -> Result<T, T> {
277	        unsafe { atomic_compare_exchange_weak(self.as_ptr(), current, new) }
278	    }
279	
280	    /// Fetches the value, and applies a function to it that returns an optional
281	    /// new value. Returns a `Result` of `Ok(previous_value)` if the function returned `Some(_)`, else
282	    /// `Err(previous_value)`.
283	    ///
284	    /// Note: This may call the function multiple times if the value has been changed from other threads in
285	    /// the meantime, as long as the function returns `Some(_)`, but the function will have been applied
286	    /// only once to the stored value.
287	    ///
288	    /// # Examples
289	    ///
290	    /// ```rust
291	    /// use crossbeam_utils::atomic::AtomicCell;
292	    ///
293	    /// let a = AtomicCell::new(7);
294	    /// assert_eq!(a.fetch_update(|_| None), Err(7));
295	    /// assert_eq!(a.fetch_update(|a| Some(a + 1)), Ok(7));
296	    /// assert_eq!(a.fetch_update(|a| Some(a + 1)), Ok(8));
297	    /// assert_eq!(a.load(), 9);
298	    /// ```
299	    #[inline]
300	    pub fn fetch_update<F>(&self, mut f: F) -> Result<T, T>
301	    where
302	        F: FnMut(T) -> Option<T>,
303	    {
304	        let mut prev = self.load();
305	        while let Some(next) = f(prev) {
306	            match self.compare_exchange(prev, next) {
307	                x @ Ok(_) => return x,
308	                Err(next_prev) => prev = next_prev,
309	            }
310	        }
311	        Err(prev)
312	    }
313	}
314	
315	// `MaybeUninit` prevents `T` from being dropped, so we need to implement `Drop`
316	// for `AtomicCell` to avoid leaks of non-`Copy` types.
317	impl<T> Drop for AtomicCell<T> {
318	    fn drop(&mut self) {
319	        if mem::needs_drop::<T>() {
320	            // SAFETY:
321	            // - the mutable reference guarantees that no other threads are concurrently accessing the atomic data
322	            // - the raw pointer passed in is valid because we got it from a reference
323	            // - `MaybeUninit` prevents double dropping `T`
324	            unsafe {
325	                self.as_ptr().drop_in_place();
326	            }
327	        }
328	    }
329	}
