377	macro_rules! impl_arithmetic {
378	    ($t:ty, #[cfg($target_has_atomic:meta)] $atomic:ident, $example:tt) => {
379	        impl AtomicCell<$t> {
380	            /// Increments the current value by `val` and returns the previous value.
381	            ///
382	            /// The addition wraps on overflow.
383	            ///
384	            /// # Examples
385	            ///
386	            /// ```
387	            /// use crossbeam_utils::atomic::AtomicCell;
388	            ///
389	            #[doc = $example]
390	            ///
391	            /// assert_eq!(a.fetch_add(3), 7);
392	            /// assert_eq!(a.load(), 10);
393	            /// ```
394	            #[inline]
395	            pub fn fetch_add(&self, val: $t) -> $t {
396	                atomic! {
397	                    $t, _a,
398	                    {
399	                        #[cfg($target_has_atomic)]
400	                        {
401	                            let a = unsafe { &*(self.as_ptr() as *const atomic::$atomic) };
402	                            a.fetch_add(val, Ordering::AcqRel)
403	                        }
404	                        #[cfg(not($target_has_atomic))]
405	                        {
406	                            self.fetch_update(|old| Some(old.wrapping_add(val))).unwrap()
407	                        }
408	                    },
409	                    {
410	                        let _guard = lock(self.as_ptr() as usize).write();
411	                        let value = unsafe { &mut *(self.as_ptr()) };
412	                        let old = *value;
413	                        *value = value.wrapping_add(val);
414	                        old
415	                    }
416	                }
417	            }
418	
419	            /// Decrements the current value by `val` and returns the previous value.
420	            ///
421	            /// The subtraction wraps on overflow.
422	            ///
423	            /// # Examples
424	            ///
425	            /// ```
426	            /// use crossbeam_utils::atomic::AtomicCell;
427	            ///
428	            #[doc = $example]
429	            ///
430	            /// assert_eq!(a.fetch_sub(3), 7);
431	            /// assert_eq!(a.load(), 4);
432	            /// ```
433	            #[inline]
434	            pub fn fetch_sub(&self, val: $t) -> $t {
435	                atomic! {
436	                    $t, _a,
437	                    {
438	                        #[cfg($target_has_atomic)]
439	                        {
440	                            let a = unsafe { &*(self.as_ptr() as *const atomic::$atomic) };
441	                            a.fetch_sub(val, Ordering::AcqRel)
442	                        }
443	                        #[cfg(not($target_has_atomic))]
444	                        {
445	                            self.fetch_update(|old| Some(old.wrapping_sub(val))).unwrap()
446	                        }
447	                    },
448	                    {
449	                        let _guard = lock(self.as_ptr() as usize).write();
450	                        let value = unsafe { &mut *(self.as_ptr()) };
451	                        let old = *value;
452	                        *value = value.wrapping_sub(val);
453	                        old
454	                    }
455	                }
456	            }
457	
458	            /// Applies bitwise "and" to the current value and returns the previous value.
459	            ///
460	            /// # Examples
461	            ///
462	            /// ```
463	            /// use crossbeam_utils::atomic::AtomicCell;
464	            ///
465	            #[doc = $example]
466	            ///
467	            /// assert_eq!(a.fetch_and(3), 7);
468	            /// assert_eq!(a.load(), 3);
469	            /// ```
470	            #[inline]
471	            pub fn fetch_and(&self, val: $t) -> $t {
472	                atomic! {
473	                    $t, _a,
474	                    {
475	                        #[cfg($target_has_atomic)]
476	                        {
477	                            let a = unsafe { &*(self.as_ptr() as *const atomic::$atomic) };
478	                            a.fetch_and(val, Ordering::AcqRel)
479	                        }
480	                        #[cfg(not($target_has_atomic))]
481	                        {
482	                            self.fetch_update(|old| Some(old & val)).unwrap()
483	                        }
484	                    },
485	                    {
486	                        let _guard = lock(self.as_ptr() as usize).write();
487	                        let value = unsafe { &mut *(self.as_ptr()) };
488	                        let old = *value;
489	                        *value &= val;
490	                        old
491	                    }
492	                }
493	            }
494	
495	            /// Applies bitwise "nand" to the current value and returns the previous value.
496	            ///
497	            /// # Examples
498	            ///
499	            /// ```
500	            /// use crossbeam_utils::atomic::AtomicCell;
501	            ///
502	            #[doc = $example]
503	            ///
504	            /// assert_eq!(a.fetch_nand(3), 7);
505	            /// assert_eq!(a.load(), !(7 & 3));
506	            /// ```
507	            #[inline]
508	            pub fn fetch_nand(&self, val: $t) -> $t {
509	                atomic! {
510	                    $t, _a,
511	                    {
512	                        #[cfg($target_has_atomic)]
513	                        {
514	                            let a = unsafe { &*(self.as_ptr() as *const atomic::$atomic) };
515	                            a.fetch_nand(val, Ordering::AcqRel)
516	                        }
517	                        #[cfg(not($target_has_atomic))]
518	                        {
519	                            self.fetch_update(|old| Some(!(old & val))).unwrap()
520	                        }
521	                    },
522	                    {
523	                        let _guard = lock(self.as_ptr() as usize).write();
524	                        let value = unsafe { &mut *(self.as_ptr()) };
525	                        let old = *value;
526	                        *value = !(old & val);
527	                        old
528	                    }
529	                }
530	            }
531	
532	            /// Applies bitwise "or" to the current value and returns the previous value.
533	            ///
534	            /// # Examples
535	            ///
536	            /// ```
537	            /// use crossbeam_utils::atomic::AtomicCell;
538	            ///
539	            #[doc = $example]
540	            ///
541	            /// assert_eq!(a.fetch_or(16), 7);
542	            /// assert_eq!(a.load(), 23);
543	            /// ```
544	            #[inline]
545	            pub fn fetch_or(&self, val: $t) -> $t {
546	                atomic! {
547	                    $t, _a,
548	                    {
549	                        #[cfg($target_has_atomic)]
550	                        {
551	                            let a = unsafe { &*(self.as_ptr() as *const atomic::$atomic) };
552	                            a.fetch_or(val, Ordering::AcqRel)
553	                        }
554	                        #[cfg(not($target_has_atomic))]
555	                        {
556	                            self.fetch_update(|old| Some(old | val)).unwrap()
557	                        }
558	                    },
559	                    {
560	                        let _guard = lock(self.as_ptr() as usize).write();
561	                        let value = unsafe { &mut *(self.as_ptr()) };
562	                        let old = *value;
563	                        *value |= val;
564	                        old
565	                    }
566	                }
567	            }
568	
569	            /// Applies bitwise "xor" to the current value and returns the previous value.
570	            ///
571	            /// # Examples
572	            ///
573	            /// ```
574	            /// use crossbeam_utils::atomic::AtomicCell;
575	            ///
576	            #[doc = $example]
577	            ///
578	            /// assert_eq!(a.fetch_xor(2), 7);
579	            /// assert_eq!(a.load(), 5);
580	            /// ```
581	            #[inline]
582	            pub fn fetch_xor(&self, val: $t) -> $t {
583	                atomic! {
584	                    $t, _a,
585	                    {
586	                        #[cfg($target_has_atomic)]
587	                        {
588	                            let a = unsafe { &*(self.as_ptr() as *const atomic::$atomic) };
589	                            a.fetch_xor(val, Ordering::AcqRel)
590	                        }
591	                        #[cfg(not($target_has_atomic))]
592	                        {
593	                            self.fetch_update(|old| Some(old ^ val)).unwrap()
