1110	/// Atomically compares data at `dst` to `current` and, if equal byte-for-byte, exchanges data at
1111	/// `dst` with `new`.
1112	///
1113	/// Returns the old value on success, or the current value at `dst` on failure.
1114	///
1115	/// This operation uses the `AcqRel` ordering. If possible, an atomic instructions is used, and a
1116	/// global lock otherwise.
1117	#[allow(clippy::let_unit_value)]
1118	unsafe fn atomic_compare_exchange_weak<T>(dst: *mut T, mut current: T, new: T) -> Result<T, T>
1119	where
1120	    T: Copy + Eq,
1121	{
1122	    atomic! {
1123	        T, a,
1124	        {
1125	            a = unsafe { &*(dst as *const _ as *const _) };
1126	            let mut current_raw = unsafe { mem::transmute_copy(&current) };
1127	            let new_raw = unsafe { mem::transmute_copy(&new) };
1128	
1129	            loop {
1130	                match a.compare_exchange_weak(
1131	                    current_raw,
1132	                    new_raw,
1133	                    Ordering::AcqRel,
1134	                    Ordering::Acquire,
1135	                ) {
1136	                    Ok(_) => break Ok(current),
1137	                    Err(previous_raw) => {
1138	                        let previous = unsafe { mem::transmute_copy(&previous_raw) };
1139	
1140	                        if !T::eq(&previous, &current) {
1141	                            break Err(previous);
1142	                        }
1143	
1144	                        // The compare-exchange operation has failed and didn't store `new`. The
1145	                        // failure is either spurious, or `previous` was semantically equal to
1146	                        // `current` but not byte-equal. Let's retry with `previous` as the new
1147	                        // `current`.
1148	                        current = previous;
1149	                        current_raw = previous_raw;
1150	                    }
1151	                }
1152	            }
1153	        },
1154	        {
1155	            let guard = lock(dst as usize).write();
1156	
1157	            let old = unsafe { ptr::read(dst) };
1158	            if T::eq(&old, &current) {
1159	                unsafe { ptr::write(dst, new) }
1160	                Ok(old)
1161	            } else {
1162	                // The value hasn't been changed. Drop the guard without incrementing the stamp.
1163	                guard.abort();
1164	                Err(old)
1165	            }
1166	        }
1167	    }
1168	}
